197	}
198	
199	export async function getRegistryBaseColor(baseColor: string) {
200	  try {
201	    const [result] = await fetchRegistry([`colors/${baseColor}.json`])
202	
203	    return registryBaseColorSchema.parse(result)
204	  } catch (error) {
205	    handleError(error)
206	  }
207	}
208	
209	/**
210	 * @deprecated This function is deprecated and will be removed in a future version.
211	 */
212	export async function resolveTree(
213	  index: z.infer<typeof registryIndexSchema>,
214	  names: string[]
215	) {
216	  const tree: z.infer<typeof registryIndexSchema> = []
217	
218	  for (const name of names) {
219	    const entry = index.find((entry) => entry.name === name)
220	
221	    if (!entry) {
222	      continue
223	    }
224	
225	    tree.push(entry)
226	
227	    if (entry.registryDependencies) {
228	      const dependencies = await resolveTree(index, entry.registryDependencies)
229	      tree.push(...dependencies)
230	    }
231	  }
232	
233	  return tree.filter(
234	    (component, index, self) =>
235	      self.findIndex((c) => c.name === component.name) === index
236	  )
237	}
238	
239	/**
240	 * @deprecated This function is deprecated and will be removed in a future version.
241	 */
242	export async function fetchTree(
243	  style: string,
244	  tree: z.infer<typeof registryIndexSchema>
245	) {
246	  try {
247	    const paths = tree.map((item) => `styles/${style}/${item.name}.json`)
248	    const results = await fetchRegistry(paths)
249	    return results.map((result) => registryItemSchema.parse(result))
250	  } catch (error) {
251	    handleError(error)
252	    return []
253	  }
254	}
255	
256	/**
257	 * @deprecated This function is deprecated and will be removed in a future version.
258	 */
259	export async function getItemTargetPath(
260	  config: Config,
261	  item: Pick<z.infer<typeof registryItemSchema>, "type">,
262	  override?: string
263	) {
264	  if (override) {
265	    return override
266	  }
267	
268	  if (item.type === "registry:ui") {
269	    return config.resolvedPaths.ui ?? config.resolvedPaths.components
270	  }
271	
272	  const [parent, type] = item.type?.split(":") ?? []
273	  if (!(parent in config.resolvedPaths)) {
274	    return null
275	  }
276	
277	  return path.join(
278	    config.resolvedPaths[parent as keyof typeof config.resolvedPaths],
279	    type
280	  )
281	}
282	
283	// Fetch registries with new schema (array of objects with name, homepage, url, featured).
284	export async function getRegistries(options?: { useCache?: boolean }) {
285	  options = {
286	    useCache: true,
287	    ...options,
288	  }
289	
290	  const url = `${REGISTRY_URL}/registries.json`
291	  const [data] = await fetchRegistry([url], {
292	    useCache: options.useCache,
293	  })
294	
295	  try {
296	    return registriesSchema.parse(data)
297	  } catch (error) {
298	    if (error instanceof z.ZodError) {
299	      throw new RegistriesIndexParseError(error)
300	    }
301	
302	    throw error
303	  }
304	}
305	
306	/**
307	 * @deprecated Use getRegistries() instead.
308	 */
309	export async function getRegistriesIndex(options?: { useCache?: boolean }) {
310	  // Fetch new format and transform to old Record<string, string> for backward compatibility.
311	  const registries = await getRegistries(options)
312	  if (!registries) return null
313	  return Object.fromEntries(registries.map((r) => [r.name, r.url])) as z.infer<
314	    typeof registriesIndexSchema
315	  >
316	}
317	
318	export async function getPresets(options?: { useCache?: boolean }) {
319	  options = {
320	    useCache: true,
321	    ...options,
322	  }
323	
324	  const url = `${REGISTRY_URL}/config.json`
325	  const [data] = await fetchRegistry([url], {
326	    useCache: options.useCache,
327	  })
328	
329	  const result = configJsonSchema.parse(data)
330	  return result.presets
331	}
332	
333	export async function getPreset(
334	  name: string,
335	  options?: { useCache?: boolean }
336	) {
337	  const presets = await getPresets(options)
338	  return (
339	    presets.find(
340	      (preset) => preset.name.toLowerCase() === name.toLowerCase()
341	    ) ?? null
342	  )
343	}
