import {
  Stepper,
  StepperDescription,
  StepperItem,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/bases/radix/ui/stepper"

export default function StepperExample() {
  return (
    <ExampleWrapper className="lg:grid-cols-1 2xl:grid-cols-1">
      <StepperBasic />
      <StepperVertical />
      <StepperWithPanels />
      <StepperInCard />
    </ExampleWrapper>
  )
}

const STEPS = ["account", "profile", "review"]

// Reusable step number/check badge
function StepBadge({
  index,
  isActive,
  isCompleted,
}: {
  index: number
  isActive: boolean
  isCompleted: boolean
}) {
  return (
    <span
      className={[
        "flex h-8 w-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors",
        isCompleted
          ? "border-primary bg-primary text-primary-foreground"
          : isActive
            ? "border-primary bg-background text-primary"
            : "border-muted-foreground/30 bg-background text-muted-foreground",
      ].join(" ")}
    >
      {isCompleted ? "✓" : index + 1}
    </span>
  )
}

function StepperBasic() {
  const [step, setStep] = React.useState(STEPS[0])

  return (
    <Example title="Basic">
      <Stepper
        value={step}
        onValueChange={setStep}
        steps={STEPS}
        className="w-full"
      >
        {STEPS.map((s, i) => {
          const isActive = step === s
          const isCompleted = STEPS.indexOf(step) > i
          return (
            <React.Fragment key={s}>
              {i > 0 && <StepperSeparator />}
              <StepperItem value={s} className="flex-1">
                <StepperTrigger className="flex flex-col items-center gap-2 p-1">
                  <StepBadge index={i} isActive={isActive} isCompleted={isCompleted} />
                  <StepperTitle
                    className={isActive ? "text-foreground" : "text-muted-foreground"}
                  >
                    {s.charAt(0).toUpperCase() + s.slice(1)}
                  </StepperTitle>
                </StepperTrigger>
              </StepperItem>
            </React.Fragment>
          )
        })}
      </Stepper>
    </Example>
  )
}

function StepperVertical() {
  const [step, setStep] = React.useState(STEPS[0])

  const items = [
    { value: "account", title: "Account", description: "Set up your account" },
    { value: "profile", title: "Profile", description: "Personalize your profile" },
    { value: "review", title: "Review", description: "Confirm your details" },
  ]

  return (
    <Example title="Vertical">
      <Stepper
        value={step}
        onValueChange={setStep}
        steps={STEPS}
        orientation="vertical"
      >
        {items.map((item, i) => {
          const isActive = step === item.value
          const isCompleted = STEPS.indexOf(step) > i
          return (
            <React.Fragment key={item.value}>
              {i > 0 && <StepperSeparator className="ml-4" />}
              <StepperItem value={item.value}>
                <StepperTrigger className="gap-3 p-1">
                  <StepBadge index={i} isActive={isActive} isCompleted={isCompleted} />
                  <div className="flex flex-col items-start gap-0.5 text-left">
                    <StepperTitle
                      className={isActive ? "text-foreground" : "text-muted-foreground"}
                    >
                      {item.title}
                    </StepperTitle>
                    <StepperDescription>{item.description}</StepperDescription>
                  </div>
                </StepperTrigger>
              </StepperItem>
            </React.Fragment>
          )
        })}
      </Stepper>
    </Example>
  )
}

function StepperWithPanels() {
  const [step, setStep] = React.useState(STEPS[0])

  const items = [
    { value: "account", title: "Account", description: "Login credentials" },
    { value: "profile", title: "Profile", description: "Personal information" },
    { value: "review", title: "Review", description: "Confirm & submit" },
  ]

  const currentIndex = STEPS.indexOf(step)

  return (
    <Example title="With Content Panels">
      {/*
        The Stepper wraps both the nav row and the panels so that
        StepperPanel can read the active value from context.
        We override the flex direction to column via className.
      */}
      <Stepper
        value={step}
        onValueChange={setStep}
        steps={STEPS}
        className="w-full flex-col gap-6"
      >
        {/* Navigation row */}
        <div className="flex w-full items-center">
          {items.map((item, i) => {
            const isActive = step === item.value
            const isCompleted = currentIndex > i
            return (
              <React.Fragment key={item.value}>
                {i > 0 && <StepperSeparator />}
                <StepperItem value={item.value} className="flex-1">
                  <StepperTrigger className="flex flex-col items-center gap-2 p-1">
                    <StepBadge
                      index={i}
                      isActive={isActive}
                      isCompleted={isCompleted}
                    />
                    <StepperTitle
                      className={
                        isActive ? "text-foreground" : "text-muted-foreground"
                      }
                    >
                      {item.title}
                    </StepperTitle>
                    <StepperDescription>{item.description}</StepperDescription>
                  </StepperTrigger>
                </StepperItem>
              </React.Fragment>
            )
          })}
        </div>

        {/* Content panels — each mounts only when its value is active */}
        <StepperPanel value="account">
          <div className="rounded-lg border p-6">
            <h3 className="mb-2 font-semibold">Create your account</h3>
            <p className="text-sm text-muted-foreground">
              Enter your email and choose a secure password to get started.
            </p>
          </div>
        </StepperPanel>
        <StepperPanel value="profile">
          <div className="rounded-lg border p-6">
            <h3 className="mb-2 font-semibold">Set up your profile</h3>
            <p className="text-sm text-muted-foreground">
              Add your name, bio, and profile picture so others can find you.
            </p>
          </div>
        </StepperPanel>
        <StepperPanel value="review">
          <div className="rounded-lg border p-6">
            <h3 className="mb-2 font-semibold">Review your information</h3>
            <p className="text-sm text-muted-foreground">
              Everything look good? Click submit to complete your setup.
            </p>
          </div>
        </StepperPanel>

        {/* Back / Next navigation */}
        <div className="flex justify-between">
          <Button
            variant="outline"
            onClick={() => setStep(STEPS[currentIndex - 1])}
            disabled={currentIndex === 0}
          >
            Back
          </Button>
          <Button
            onClick={() => {
              if (currentIndex < STEPS.length - 1) {
                setStep(STEPS[currentIndex + 1])
              }
            }}
            disabled={currentIndex === STEPS.length - 1}
          >
            Next
          </Button>
        </div>
      </Stepper>
    </Example>
  )
}

function StepperInCard() {
  const [step, setStep] = React.useState(STEPS[0])

  return (
    <Example title="In Card">
      <Card className="mx-auto w-full max-w-lg">
        <CardHeader>
          <CardTitle>Onboarding</CardTitle>
          <CardDescription>
            Complete these steps to finish your setup.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <Stepper
            value={step}
            onValueChange={setStep}
            steps={STEPS}
            className="w-full"
          >
            {STEPS.map((s, i) => {
              const isActive = step === s
              const isCompleted = STEPS.indexOf(step) > i
              return (
                <React.Fragment key={s}>
                  {i > 0 && <StepperSeparator />}
                  <StepperItem value={s} className="flex-1">
                    <StepperTrigger className="flex flex-col items-center gap-2 p-1">
                      <StepBadge
                        index={i}
                        isActive={isActive}
                        isCompleted={isCompleted}
                      />
                      <StepperTitle
                        className={
                          isActive ? "text-foreground" : "text-muted-foreground"
                        }
                      >
                        {s.charAt(0).toUpperCase() + s.slice(1)}
                      </StepperTitle>
                    </StepperTrigger>
                  </StepperItem>
                </React.Fragment>
              )
            })}
          </Stepper>
        </CardContent>
      </Card>
    </Example>
  )
}

