                          className={
                            isActive
                              ? "text-foreground"
                              : "text-muted-foreground"
                          }
                        >
                          {s.charAt(0).toUpperCase() + s.slice(1)}
                        </StepperTitle>
                      </>
                    )}
                  </StepperTrigger>
                </StepperItem>
              </React.Fragment>
            ))}
          </Stepper>
        </CardContent>
      </Card>
    </Example>
  )
}

// Standalone helper used in StepperWithPanels to read active step
// without coupling to StepperContext (the Stepper is a sibling, not ancestor)
function StepperPanel({
  value,
  currentStep,
  steps: _steps,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
  currentStep: string
  steps?: string[]
}) {
  if (value !== currentStep) return null
  return <div {...props}>{children}</div>
}

