"use client"

import * as React from "react"

import { cn } from "@/registry/bases/radix/lib/utils"

// ─── Root Context ─────────────────────────────────────────────────────────────

type StepperContextProps = {
  value: string
  onValueChange: (value: string) => void
  orientation: "horizontal" | "vertical"
  steps: string[]
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a Stepper.")
  }
  return context
}

// ─── Item Context ─────────────────────────────────────────────────────────────

type StepperItemContextProps = {
  value: string
  isActive: boolean
  isCompleted: boolean
  isPending: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a StepperItem.")
  }
  return context
}

// ─── Stepper (root) ──────────────────────────────────────────────────────────

function Stepper({
  value: valueProp,
  defaultValue,
  onValueChange,
  orientation = "horizontal",
  steps = [],
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: "horizontal" | "vertical"
  steps?: string[]
}) {
  const [_value, _setValue] = React.useState(defaultValue ?? steps[0] ?? "")
  const value = valueProp ?? _value

  const handleValueChange = React.useCallback(
    (next: string) => {
      if (onValueChange) {
        onValueChange(next)
      } else {
        _setValue(next)
      }
    },
    [onValueChange]
  )

  const contextValue = React.useMemo<StepperContextProps>(
    () => ({
      value,
      onValueChange: handleValueChange,
      orientation,
      steps,
    }),
    [value, handleValueChange, orientation, steps]
  )

  return (
    <StepperContext.Provider value={contextValue}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper group/stepper flex data-vertical:flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ─────────────────────────────────────────────────────────────

function StepperItem({
  value,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
}) {
  const { value: activeValue, steps } = useStepper()

  const activeIndex = steps.indexOf(activeValue)
  const itemIndex = steps.indexOf(value)

  const isActive = value === activeValue
  const isCompleted =
    itemIndex !== -1 && activeIndex !== -1 && itemIndex < activeIndex
  const isPending = !isActive && !isCompleted

  const itemContext = React.useMemo<StepperItemContextProps>(
    () => ({ value, isActive, isCompleted, isPending }),
    [value, isActive, isCompleted, isPending]
  )

  return (
    <StepperItemContext.Provider value={itemContext}>
      <div
        data-slot="stepper-item"
        data-active={isActive ? "" : undefined}
        data-completed={isCompleted ? "" : undefined}
        data-pending={isPending ? "" : undefined}
        className={cn(
          "cn-stepper-item flex flex-col items-center gap-2",
          "group-data-vertical/stepper:flex-row group-data-vertical/stepper:items-start",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ──────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { value, isActive, isCompleted, isPending } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-active={isActive ? "" : undefined}
      data-completed={isCompleted ? "" : undefined}
      data-pending={isPending ? "" : undefined}
      aria-current={isActive ? "step" : undefined}
      onClick={() => onValueChange(value)}
      className={cn(
        "cn-stepper-trigger inline-flex items-center gap-2 rounded outline-none",
        "focus-visible:ring-ring/50 focus-visible:ring-2",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn(
        "cn-stepper-title text-sm font-medium leading-none",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ──────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-xs text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperSeparator ────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      aria-hidden
      className={cn(
        "cn-stepper-separator shrink-0 bg-border",
        "data-horizontal:h-px data-horizontal:flex-1 data-horizontal:self-center",
        "data-vertical:w-px data-vertical:min-h-6 data-vertical:self-stretch",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperPanel ────────────────────────────────────────────────────────────

function StepperPanel({
  value,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
}) {
  const { value: activeValue } = useStepper()

  if (value !== activeValue) {
    return null
  }

  return (
    <div
      data-slot="stepper-panel"
      className={cn("cn-stepper-panel flex-1", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
}

